sp_widget.client_script:
api.controller = function() {
  var c = this;
  c.data = c.data || {};
  c.activeTab = 'my';

  c.setTab = function(tab) {
    c.activeTab = tab;
  };

  c.getStateClass = function(state) {
    if (!state) return 'label-default';
    var s = state.toLowerCase();
    if (s === 'open' || s === 'pending') return 'label-info';
    if (s === 'work in progress') return 'label-warning';
    if (s === 'closed complete') return 'label-success';
    return 'label-default';
  };
};

sp_widget.css:
.sp-table-wrapper { border: 1px solid $border-tertiary; border-radius: $border-radius-large; overflow: hidden; background: $background-primary; margin-top: 16px; }
.sp-th { font-size: 12px; font-weight: 600; color: $text-muted; text-transform: uppercase; letter-spacing: 0.04em; padding: 12px 16px; border-bottom: 2px solid $border-tertiary; background: $background-secondary; }
.sp-td { font-size: $font-size-small; padding: 12px 16px; color: $text-color; border-bottom: 1px solid $border-tertiary; vertical-align: middle; }
.sp-empty-state { padding: 48px 24px; }
.sp-empty-icon { font-size: 48px; margin-bottom: 16px; display: block; opacity: 0.35; color: $text-muted; }
.sp-empty-title { font-size: $font-size-large; font-weight: 600; color: $text-color; margin-bottom: 8px; }
.nav-tabs { margin-bottom: 0; }
.nav-tabs > li > a { cursor: pointer; }

sp_widget.script:
(function() {
  data.myCases = [];
  data.highPriority = [];
  data.errorMsg = '';

  try {
    var userId = gs.getUserID();
    var tableName = 'x_2091449_manage_0_consumer_case';

    // My assigned cases
    var myGr = new GlideRecord(tableName);
    myGr.addQuery('assigned_to', userId);
    myGr.addQuery('active', true);
    myGr.orderByDesc('priority');
    myGr.orderByDesc('sys_created_on');
    myGr.setLimit(25);
    myGr.query();
    while (myGr.next()) {
      data.myCases.push({
        sys_id: myGr.getUniqueValue(),
        number: myGr.getValue('number') + '',
        short_description: myGr.getValue('short_description') + '',
        state: myGr.getDisplayValue('state') + '',
        priority: myGr.getDisplayValue('priority') + '',
        opened_at: myGr.getDisplayValue('opened_at') + '',
        customer_name: myGr.getValue('customer_name') + ''
      });
    }

    // High priority unassigned queue
    var hpGr = new GlideRecord(tableName);
    hpGr.addQuery('priority', 'IN', '1,2');
    hpGr.addQuery('active', true);
    hpGr.addNullQuery('assigned_to');
    hpGr.orderBy('priority');
    hpGr.orderByDesc('sys_created_on');
    hpGr.setLimit(15);
    hpGr.query();
    while (hpGr.next()) {
      data.highPriority.push({
        sys_id: hpGr.getUniqueValue(),
        number: hpGr.getValue('number') + '',
        short_description: hpGr.getValue('short_description') + '',
        state: hpGr.getDisplayValue('state') + '',
        priority: hpGr.getDisplayValue('priority') + '',
        opened_at: hpGr.getDisplayValue('opened_at') + '',
        customer_name: hpGr.getValue('customer_name') + ''
      });
    }
  } catch (e) {
    gs.error('Agent Queue widget error: ' + e.message);
    data.errorMsg = 'An error occurred loading the agent queue.';
  }
})();
